### express.json()

Parses incoming JSON payloads:

```javascript
app.use(express.json());

app.post('/users', (req, res) => {
  console.log(req.body.name);
  console.log(req.body.email);
});
```

### express.urlencoded()

Parses form data (application/x-www-form-urlencoded):

```javascript
app.use(express.urlencoded({ extended: true }));
// extended: true allows parsing of nested objects
```

With `extended: false`, values are strings or arrays only. With `extended: true`, nested objects are supported.

### Parsing Nested Objects

With `extended: true`, form data like `user[name]=John&user[age]=30` parses to:

```javascript
{ user: { name: 'John', age: '30' } }
```

### Body Size Limits

Limit request body size:

```javascript
app.use(express.json({ limit: '10kb' }));
app.use(express.urlencoded({ limit: '5mb', extended: true }));
```

### Raw Text Parsing

Parse plain text bodies:

```javascript
app.use(express.text());

app.post('/raw', (req, res) => {
  console.log(req.body); // string
});
```

codeExample:
const express = require('express');
const app = express();

app.use(express.json({ limit: '1mb' }));
app.use(express.urlencoded({ extended: true, limit: '1mb' }));

app.post('/api/register', (req, res) => {
  const { username, email, password } = req.body;
  res.status(201).json({ username, email });
});
